// Test current date detection
const now = new Date();
const mountainTime = new Date(now.toLocaleString("en-US", {timeZone: "America/Denver"}));

const output = {
  monthDay: `${mountainTime.getMonth() + 1}/${mountainTime.getDate()}`,
  dayOfWeek: mountainTime.toLocaleDateString('en-US', { weekday: 'long' }),
  today: mountainTime.toLocaleDateString('en-US', { 
    weekday: 'long', 
    year: 'numeric', 
    month: 'long', 
    day: 'numeric' 
  })
};

console.log('Current Mountain Time date info:', output);
return output;

// Test readings lookup with debug
const dateInfo = $json;

console.log('=== READINGS DEBUG START ===');
console.log('Input dateInfo:', JSON.stringify(dateInfo, null, 2));
console.log('dateInfo.monthDay:', dateInfo.monthDay);
console.log('typeof dateInfo.monthDay:', typeof dateInfo.monthDay);

// Test readings database
const readingsDatabase = {
  '8/26': { 
    firstReading: '1 Thessalonians 2:1-8', 
    psalm: 'Psalm 139:1-3, 4-6', 
    gospel: 'Matthew 23:23-26', 
    season: 'Ordinary Time' 
  },
  '8/27': { 
    firstReading: '1 Thessalonians 2:9-13', 
    psalm: 'Psalm 139:7-8, 9-10, 11-12ab', 
    gospel: 'Matthew 23:27-32', 
    season: 'Ordinary Time' 
  }
};

const currentDate = dateInfo.monthDay;
console.log('Looking up readings for date:', currentDate);

const foundReadings = readingsDatabase[currentDate];
console.log('Found readings:', JSON.stringify(foundReadings, null, 2));

if (!foundReadings) {
  console.log('No readings found! Available dates in database:');
  console.log(Object.keys(readingsDatabase));
}

console.log('=== READINGS DEBUG END ===');

return {
  ...dateInfo,
  readings: foundReadings || {
    firstReading: `NO MATCH for ${currentDate}`,
    psalm: `Available: ${Object.keys(readingsDatabase).join(', ')}`,
    gospel: `Debug - dateInfo.monthDay was: '${currentDate}'`
  }
};
